            margin: 0 auto;
            padding: 20px;
            line-height: 1.6;
        }
        .controls {
            margin-bottom: 20px;
            padding: 15px;
            background: #f0f0f0;
            border-radius: 5px;
        }
        button {
            padding: 8px 12px;
            margin-right: 5px;
            cursor: pointer;
        }
        input {
            padding: 8px;
            width: 60px;
        }
        .tree-container {
            overflow: auto;
            margin-top: 20px;
        }
        .node {
            border: 1px solid #999;
            border-radius: 3px;
            padding: 5px;
            margin: 5px;
            display: inline-block;
            background: white;
            box-shadow: 0 2px 5px rgba(0,0,0,0.1);
        }
        .internal-node {
            background: #e6f7ff;
        }
        .leaf-node {
            background: #e8f5e9;
        }
        .key {
            display: inline-block;
            padding: 3px 6px;
            margin: 2px;
            border: 1px solid #ddd;
            border-radius: 3px;
            background: white;
        }
        .pointer {
            color: #666;
            font-style: italic;
        }
        .leaf-link {
            display: inline-block;
            width: 20px;
            text-align: center;
            color: #2196F3;
        }
        .level {
            text-align: center;
            margin: 10px 0;
            white-space: nowrap;
        }
        .explanation {
            margin-top: 30px;
            padding: 15px;
            background: #f9f9f9;
