                this.minKeysInternal = Math.ceil(order / 2) - 1;
                this.minKeysLeaf = Math.floor(order / 2);
                this.root = new LeafNode([], [], null);
            }

            insert(key, value) {
                const [newChild, splitKey] = this.root.insert(key, value);

                if (newChild) {
                    const newRoot = new InternalNode([splitKey], [this.root, newChild]);
                    this.root = newRoot;
                }
            }

            delete(key) {
                const result = this.root.delete(key);

                if (result && this.root.keys.length === 0 && this.root.children) {
                    this.root = this.root.children[0];
                }

                return result;
            }

            search(key) {
                return this.root.search(key);
            }

            visualize() {
                return this.root.visualize();
            }
        }

